%[text] # 例2.4（ヒストグラム均等化）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example2_04"; % mfilename

imgname = "msipimg08";
imgfmt = "tiff";
%%
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
X = imresize(rgb2gray(imread(imgfile,imgfmt)),[96 96],'bilinear');

%%
%[text] ## 処理前の画像表示
figure(1) %[output:1604d60b]
imshow(X)  %[output:1604d60b]
title('原画像')  %[output:1604d60b]

imwrite(X,fullfile(resfolder,"fig02-05a.png"))

%%
%[text] ## 処理前のヒストグラム表示
figure(2) %[output:5abc9300]
%imhist(X,256) 
[hx,indx] = histcounts(X(:),0:256);
bar(indx(1:256),hx,'FaceColor',[0.5 0.5 0.5],'EdgeColor','none') %[output:5abc9300]
axis([0 255 0 250])  %[output:5abc9300]
daspect([256 250 1]) %[output:5abc9300]
ylabel("$h_x$",'Interpreter','latex') %[output:5abc9300]
yticks([0 100 200 ])  %[output:5abc9300]
xlabel("$x$",'Interpreter','latex') %[output:5abc9300]
ax = gca;
set(ax,'FontSize',16) %[output:5abc9300]

exportgraphics(ax,fullfile(resfolder,"fig02-05b.png"),'BackgroundColor','white') %[output:5abc9300]

%%
%[text] ## 処理前のヒストグラム均等化
Y = histeq(X,256);
figure(3) %[output:1a9db53f]
imshow(Y) %[output:1a9db53f]
title('処理画像') %[output:1a9db53f]

imwrite(Y,fullfile(resfolder,"fig02-06a.png"))
%%
%[text] ## 処理後のヒストグラム表示
figure(4) %[output:3bc47cbd]
%imhist(Y,256) 
[hy,indy] = histcounts(Y(:),0:256);
bar(indy(1:256),hy,'FaceColor',[0.5 0.5 0.5],'EdgeColor','none') %[output:3bc47cbd]
axis([0 255 0 250])  %[output:3bc47cbd]
daspect([256 250 1]) %[output:3bc47cbd]
ylabel("$h_y$",'Interpreter','latex') %[output:3bc47cbd]
yticks([0 100 200 ])  %[output:3bc47cbd]
xlabel("$y$",'Interpreter','latex') %[output:3bc47cbd]
ax = gca;
set(ax,'FontSize',16) %[output:3bc47cbd]

exportgraphics(ax,fullfile(resfolder,"fig02-06b.png"),'BackgroundColor','white') %[output:3bc47cbd]

